UPDATE attraction
SET attraction_name = '梅庭(目前暫停開放)', description = '※梅庭目前進行修復再利用工程，於113/5/28起閉館整修，預計115年開館

「北投梅庭」約建於1930年代末期，是一棟見證戰爭時代與順應北投風土而建的和洋式別莊。屹立在北投公園近百年，自日本時代起，所有者包括日本總督府、陸軍大臣、台北州，1945年二次世界大戰後，主要作為私人住宅使用，2006年因其建築特色登錄為臺北市歷史建築。

順地勢臨靠北投溪而建，將建物南側之山景與北投溪流結合為一，上層為日式木構架，下層為RC構造(鋼筋混凝土建築Reinforced Concrete)之地下室，作為防空避難室用，在當時代的日式街屋裡，顯得獨特與具有歷史價值。外門柱有書法家于右任題字之「梅庭」門牌，庭院內有受「臺北市樹木保護自治條例」保護之臺北市保護樟樹(編號1679)，週邊圍牆以停採之「唭哩岸石」為建材，屋內空間配置講究，利用北投豐富的地熱資源，曾設置「溫泉浴室」， 建有「閣樓」瞭望、儲藏物品，並有調節室內溫度、排濕防潮功能，同時也作為下層樓面的天花板以及支撐建築主要結構所在；玄關處貼有「釉面馬賽克」磁磚加上洗石子的門柱，彰顯工藝之美，牆面上的「八角窗」設計，為日本時代興起之擬洋風裝飾，內斂雅致，更是顯出富有有時代感與建造之美。

2021年由臺北市文化局委任台北市文化基金會營運維護，為提升文化資產再利用與在地推廣，未來將延續北投特有的人文特色，透過藝術展覽、教育活動，創造歷史人文與藝術文化相結合的樂活空間。', is_active = TRUE
WHERE attraction_name = '梅庭';
DELETE iu FROM image_url iu
JOIN attraction a ON iu.attraction_id = a.id
WHERE a.attraction_name = '梅庭(目前暫停開放)';

UPDATE attraction
SET attraction_name = '臺北自來水園區', description = '座落於公館商圈旁的臺北自來水園區，是一處完美融合歷史古蹟、工業遺產、親子遊樂與環境教育的多元化休閒空間。園區的核心，無疑是那座被列為國家三級古蹟的自來水博物館。這棟建於1908年（日治時期）的臺北水道地唧筒室（即抽水站），是臺灣近代自來水系統的起點，其建築本身就是一件藝術品，成為臺北熱門的婚紗攝影與外拍聖地之一。走進博物館內部，挑高的空間依然保存著當年運作的大型柴油馬達、抽水幫浦與配電盤等機組設備，讓遊客能親身感受百年前工業時代的震撼脈動。

一到炎炎夏日，這裡便會化身為親子樂園。廣闊的園區內設有水鄉庭園與親水體驗區，提供大型戲水池、滑水道、噴泉與水砲等豐富設施，是孩子們消暑的最佳去處；而非夏季期間，這裡也是一片適合散步休憩的開闊廣場。此外，園區內還隱藏著一條觀音山生態步道，步道綠意盎然，登頂後可探訪同樣具有歷史的觀音山蓄水池。除了休閒功能，園區也肩負著水資源的教育使命，透過互動裝置與展覽，向大眾傳遞水資源保育的重要性。從百年古蹟的建築之美、夏日限定的沁涼歡笑，到生態步道的自然綠意，臺北自來水園區已成為一個適合全家大小，兼具知性與感性的城市綠洲。', is_active = TRUE
WHERE attraction_name = '自來水博物館';
