UPDATE attraction
SET attraction_name = '國民革命忠烈祠', description = '背倚青山、面臨基隆河的「國民革命忠烈祠」，是中華民國崇祀殉國將士的最高殿堂。其建築群極為宏偉壯麗，仿照北京故宮太和殿結構而建，整體格局氣勢磅礴，一踏入便能感受到莊嚴肅穆的氛圍。

忠烈祠最吸引國內外遊客目光的，莫過於每個整點上演的「三軍儀隊交接儀式」。由陸、海、空三軍儀隊輪流擔任的衛兵，身穿筆挺的軍服，手持擦得雪亮的鋼槍，以一絲不苟、分毫不差的精準步伐，在廣闊的廣場上進行交接展演。從大門走到大殿的儀式中，他們穩健的步伐、響亮的鞋釘聲，以及高難度的耍槍動作，完美展現了軍人的儀態與紀律。在衛兵哨位上，他們必須如雕像般紋風不動，不論風吹日曬，堅毅地守護著這座英靈聖殿，這場結合力與美的儀式，已成為忠烈祠最生動的象徵。', is_active = TRUE
WHERE attraction_name = '臺北忠烈祠';
